    public int minReversals(String s) {
        if (s.length() % 2 != 0) return -1;
        Stack<Character> stack = new Stack<>();
        for (char c : s.toCharArray()) {
            if (c == '{') stack.push(c);
            else if (!stack.isEmpty() && stack.peek() == '{') stack.pop();
